
getgenv().UpdateDiamondData = function(AddPlayerData)
    local success = pcall(function()
        local placeId = game.PlaceId

        if placeId == 3823781113 or placeId == 96522925012827 then
            local diamond = game.Players.LocalPlayer.PlayerGui.MainGui.StartFrame.Currency.Diamonds.Amount
            if diamond and diamond.Text then
                AddPlayerData("Diamond 💎", diamond.Text)
            end
        end
      
    end)
    return success
end










